import React from "react";
import { Bar } from "react-chartjs-2";

import {
  Chart as ChartJS,
  CategoryScale,
  LinearScale,
  BarElement,
  Title,
  Tooltip,
  Legend,
} from "chart.js";

ChartJS.register(
  CategoryScale,
  LinearScale,
  BarElement,
  Title,
  Tooltip,
  Legend,
);

function Analytics() {
  const data = {
    labels: ["CSE", "IT", "EXTC", "Mechanical"],
    datasets: [
      {
        label: "Placed Students",
        data: [40, 25, 18, 10],
        backgroundColor: "#2563eb",
      },
    ],
  };

  return (
    <Layout>
      <h1>Placement Analytics</h1>

      <div style={{ width: "600px" }}>
        <Bar data={data} />
      </div>
    </Layout>
  );
}

export default Analytics;
